#ifndef BLOCK_SIZE
#define BLOCK_SIZE 16
#endif

#define IN_RANGE(x, min, max) ((x) >= (min) && (x) <= (max))

__kernel void hotspot(const int iteration,
                      __global const float *power,
                      __global const float *temp_src,
                      __global float *temp_dst,
                      const int col,
                      const int row,
                      const int border_cols,
                      const int border_rows,
                      const float Cap,
                      const float Rx,
                      const float Ry,
                      const float Rz,
                      const float step)
{
    const int tx = (int)get_local_id(0);
    const int ty = (int)get_local_id(1);
    const int bx = (int)get_group_id(0);
    const int by = (int)get_group_id(1);

    const int small_block_cols = BLOCK_SIZE - (border_cols << 1);
    const int small_block_rows = BLOCK_SIZE - (border_rows << 1);

    const int blkX = small_block_cols * bx - border_cols;
    const int blkY = small_block_rows * by - border_rows;

    const int xidx = blkX + tx;
    const int yidx = blkY + ty;

    const int index = yidx * col + xidx;

    const int validXmin = (blkX < 0) ? -blkX : 0;
    const int validYmin = (blkY < 0) ? -blkY : 0;
    const int validXmax = ((blkX + BLOCK_SIZE) > col) ? (col - blkX) : BLOCK_SIZE;
    const int validYmax = ((blkY + BLOCK_SIZE) > row) ? (row - blkY) : BLOCK_SIZE;

    const float stepDivCap = step / Cap;
    const float ce = stepDivCap / Rx;
    const float cw = ce;
    const float cn = stepDivCap / Ry;
    const float cs = cn;
    const float ct = stepDivCap / Rz;

    __local float temp_on_cuda[BLOCK_SIZE][BLOCK_SIZE];
    __local float power_on_cuda[BLOCK_SIZE][BLOCK_SIZE];
    __local float temp_t[BLOCK_SIZE][BLOCK_SIZE];

    if (IN_RANGE(tx, validXmin, validXmax - 1) && IN_RANGE(ty, validYmin, validYmax - 1)) {
        temp_on_cuda[ty][tx] = temp_src[index];
        power_on_cuda[ty][tx] = power[index];
    } else {
        temp_on_cuda[ty][tx] = 0.0f;
        power_on_cuda[ty][tx] = 0.0f;
    }

    barrier(CLK_LOCAL_MEM_FENCE);

    for (int i = 0; i < iteration; i++) {
        int computed = 0;

        if (IN_RANGE(tx, i + 1, BLOCK_SIZE - i - 2) &&
            IN_RANGE(ty, i + 1, BLOCK_SIZE - i - 2) &&
            IN_RANGE(tx, validXmin + i, validXmax - i - 1) &&
            IN_RANGE(ty, validYmin + i, validYmax - i - 1)) {

            const float center = temp_on_cuda[ty][tx];
            const float north = (yidx == 0)      ? center : temp_on_cuda[ty - 1][tx];
            const float south = (yidx == row - 1)? center : temp_on_cuda[ty + 1][tx];
            const float west  = (xidx == 0)      ? center : temp_on_cuda[ty][tx - 1];
            const float east  = (xidx == col - 1)? center : temp_on_cuda[ty][tx + 1];

            const float delta =
                (power_on_cuda[ty][tx] +
                 (south + north - 2.0f * center) * cs +
                 (east + west - 2.0f * center) * ce +
                 (80.0f - center) * ct);

            temp_t[ty][tx] = center + delta;
            computed = 1;
        }

        barrier(CLK_LOCAL_MEM_FENCE);

        if (computed) {
            temp_on_cuda[ty][tx] = temp_t[ty][tx];
        }

        barrier(CLK_LOCAL_MEM_FENCE);
    }

    if (IN_RANGE(tx, border_cols, BLOCK_SIZE - border_cols - 1) &&
        IN_RANGE(ty, border_rows, BLOCK_SIZE - border_rows - 1) &&
        IN_RANGE(tx, validXmin, validXmax - 1) &&
        IN_RANGE(ty, validYmin, validYmax - 1)) {
        temp_dst[index] = temp_on_cuda[ty][tx];
    }
}
